(2973, NULL, 'რამდენი სანტიმეტრია, 3 საათიანი ცეცხლმედეგობის ხარისხის მქონე სტრუქტურული ნაწილების მინიმალური დამცავის სისქე, დროის პერიოდების საფუძველზე, ბეტონისთვის კაჟბადის შემვსებით, სადაც სტრუქტურული ნაწილები 30 სმ × 30 სმ ან მეტია?', NULL, '2025-02-28 01:57:59', '2025-02-28 01:57:59'),
(2974, NULL, 'რამდენ საათიანი ცეცხლმედეგობის ხარისხი აქვს 2,5 სანტიმერტიანი სისქის სტრუქტურული ნაწილების დამცავს, სადაც სტრუქტურული ნაწილები 20 სმ × 20 სმ ან მეტია და არის ბეტონის კაჟბადის შემვსებით?', NULL, '2025-02-28 01:58:58', '2025-02-28 01:58:58'),
(2975, NULL, 'რა ცეცხლმედეგობის ხარისხი აქვს თიხის ან ფიქალის მასიური აგურის კედელს ან ტიხარს თუ კედლის მაქსიმალური სისქე 9,7 სმ-ია', NULL, '2025-02-28 01:59:59', '2025-02-28 01:59:59'),
(2976, NULL, 'რა მინიმალური სისქე უნდა ქონდეს სამ საათიანი ცეცხლმედეგობის ხარისხის ღრუტანიანი, ამოუვსებელი აგურის კედელს ან ტიხარს?', NULL, '2025-02-28 02:00:49', '2025-02-28 02:00:49'),
(2977, NULL, 'რამდენი სანტიმეტრია, 2 საათიანი ცეცხლმედეგობის ხარისხის მქონე იატაკისა და სახურავის სისტემებისათვის მინიმალური დამცავის სისქე, თუ იატაკისა და სახურავის სისტემა დამზადებულია ბეტონით, კაჟბადის შემვსებით?', NULL, '2025-02-28 02:01:51', '2025-02-28 02:01:51'),
